type Role int

const (
	Player Role = iota
	Moderator
	Admin
)

func RoleFromString(s string) Role {
	switch strings.ToLower(s) {
	case "admin":
		return Admin
	case "moderator":
		return Moderator
	default:
		return Player
	}
}

func roleToString(r Role) string {
	switch r {
	case Admin:
		return "Admin"
	case Moderator:
		return "Moderator"
	case Player:
		return "Player"
	default:
		return "Unknown"
	}
}

func IsAuthorized(userRole, requiredRole Role) bool {
	return userRole >= requiredRole
}

type ChatMessage struct {
	User    string `json:"user"`
	Message string `json:"message"`
}

type CommandArg struct {
	Name  string
	Value string
}

type Command struct {
	Name        string
	MinRole     Role
	Description string
	Handler     func(args []CommandArg, senderRole Role) string
}

var (
	commands     = make(map[string]Command)
	commandMutex sync.RWMutex
)

func RegisterCommand(cmd Command) {
	commandMutex.Lock()
	defer commandMutex.Unlock()
	commands[strings.ToLower(cmd.Name)] = cmd
}

func parseCommand(msg string) (string, []CommandArg, bool) {
	if !strings.HasPrefix(msg, "/") {
		return "", nil, false
	}

	parts := strings.Fields(msg[1:])
	if len(parts) == 0 {
		return "", nil, false
	}

	commandName := strings.ToLower(parts[0])
	var args []CommandArg
	for i := 1; i < len(parts); i++ {
		argPart := parts[i]
		if strings.Contains(argPart, "=") {
			kv := strings.SplitN(argPart, "=", 2)
			args = append(args, CommandArg{Name: kv[0], Value: kv[1]})
		} else {
			args = append(args, CommandArg{Name: fmt.Sprintf("arg%d", i), Value: argPart})
		}
	}
	return commandName, args, true
}

func chatHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Only POST method is allowed", http.StatusMethodNotAllowed)
		return
	}

	userRoleStr := r.Header.Get("X-User-Role")
	userRole := RoleFromString(userRoleStr)

	var msg ChatMessage
	err := json.NewDecoder(r.Body).Decode(&msg)
	if err != nil {
		http.Error(w, "Invalid request body", http.StatusBadRequest)
		return
	}

	log.Printf("Received message from %s (Role: %s): %s", msg.User, userRoleStr, msg.Message)

	commandName, args, isCommand := parseCommand(msg.Message)

	if isCommand {
		commandMutex.RLock()
		cmd, exists := commands[commandName]
		commandMutex.RUnlock()

		if !exists {
			log.Printf("User %s tried to execute unknown command: %s", msg.User, commandName)
			w.WriteHeader(http.StatusOK)
			fmt.Fprintf(w, "Server: Unknown command: %s", commandName)
			return
		}

		if !IsAuthorized(userRole, cmd.MinRole) {
			log.Printf("User %s (Role: %s) attempted unauthorized command: %s (Required: %s)",
				msg.User, userRoleStr, commandName, roleToString(cmd.MinRole))
			http.Error(w, "Unauthorized: Insufficient role to execute this command", http.StatusForbidden)
			return
		}

		response := cmd.Handler(args, userRole)
		log.Printf("Command '%s' executed by %s. Response: %s", commandName, msg.User, response)
		w.WriteHeader(http.StatusOK)
		fmt.Fprintf(w, "Server: %s", response)
		return
	}

	log.Printf("Chat message from %s: %s", msg.User, msg.Message)
	w.WriteHeader(http.StatusOK)
	fmt.Fprintf(w, "Server: Message received and processed as regular chat.")
}

